import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define custom CUDA kernel for optimized matrix multiplication
matmul_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cassert>

// Using shared memory for tile-based matrix multiplication
__global__ void matmul_kernel(const float* A, const float* B, float* C, 
                              int M, int N, int K) {
    const int TILE_SIZE = 32;
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int bx = blockIdx.x, by = blockIdx.y;
    int tx = threadIdx.x, ty = threadIdx.y;

    int row = by * TILE_SIZE + ty;
    int col = bx * TILE_SIZE + tx;

    float sum = 0.0f;

    for (int tile = 0; tile < (K + TILE_SIZE - 1) / TILE_SIZE; ++tile) {
        // Load tile from A (M x K)
        if (row < M && (tile * TILE_SIZE + tx) < K) {
            As[ty][tx] = A[row * K + (tile * TILE_SIZE + tx)];
        } else {
            As[ty][tx] = 0.0f;
        }

        // Load tile from B (K x N)
        if ((tile * TILE_SIZE + ty) < K && col < N) {
            Bs[ty][tx] = B[(tile * TILE_SIZE + ty) * N + col];
        } else {
            Bs[ty][tx] = 0.0f;
        }

        __syncthreads();

        // Compute partial sum
        for (int k = 0; k < TILE_SIZE; ++k) {
            sum += As[ty][k] * Bs[k][tx];
        }

        __syncthreads();
    }

    // Write result (M x N)
    if (row < M && col < N) {
        C[row * N + col] = sum;
    }
}

torch::Tensor matmul_cuda(torch::Tensor A, torch::Tensor B) {
    // Validate inputs
    TORCH_CHECK(A.dim() == 2 && B.dim() == 2, "Inputs must be 2D matrices");
    TORCH_CHECK(A.size(1) == B.size(0), "Matrix dimensions incompatible for multiplication");
    TORCH_CHECK(A.scalar_type() == torch::kFloat32 && B.scalar_type() == torch::kFloat32, 
                "Inputs must be float32");

    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(1);

    auto C = torch::zeros({M, N}, A.options());

    const int TILE_SIZE = 32;
    dim3 blockDim(TILE_SIZE, TILE_SIZE);
    dim3 gridDim((N + TILE_SIZE - 1) / TILE_SIZE, (M + TILE_SIZE - 1) / TILE_SIZE);

    matmul_kernel<<<gridDim, blockDim>>>(
        A.data_ptr<float>(),
        B.data_ptr<float>(),
        C.data_ptr<float>(),
        M, N, K
    );

    return C;
}
"""

matmul_cpp_source = "torch::Tensor matmul_cuda(torch::Tensor A, torch::Tensor B);"

# Compile the inline CUDA code
matmul_cuda = load_inline(
    name="matmul_cuda",
    cpp_sources=matmul_cpp_source,
    cuda_sources=matmul_source,
    functions=["matmul_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=["-lcublas"],
)

class ModelNew(nn.Module):
    """
    Optimized model with custom CUDA kernel for matrix multiplication
    """
    def __init__(self, expected_size=2048):
        super(ModelNew, self).__init__()
        self.matmul_cuda = matmul_cuda
        self.expected_size = expected_size  # Document expected shape

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        """
        Performs optimized matrix multiplication using custom CUDA kernel.

        Args:
            A (torch.Tensor): Input matrix A of shape (N, N).
            B (torch.Tensor): Input matrix B of shape (N, N).

        Returns:
            torch.Tensor: Output matrix C of shape (N, N).
        """
        # Validate input shapes match expected contract
        if A.dim() != 2 or B.dim() != 2:
            raise ValueError(f"Inputs must be 2D matrices, got A.shape={A.shape}, B.shape={B.shape}")
        if A.size(0) != A.size(1) or B.size(0) != B.size(1):
            raise ValueError(f"Inputs must be square matrices, got A.shape={A.shape}, B.shape={B.shape}")
        if A.size(0) != self.expected_size or B.size(0) != self.expected_size:
            raise ValueError(f"Input size must be {self.expected_size}, got A.shape={A.shape}, B.shape={B.shape}")
        if A.size(0) != B.size(0):
            raise ValueError(f"Input matrices must have same size, got A.shape={A.shape}, B.shape={B.shape}")

        return self.matmul_cuda.matmul_cuda(A, B)

